// Std
use std::ffi::OsString;
use std::mem;
use std::ops::Deref;

// Internal
use crate::builder::{Arg, ArgPredicate, Command};
use crate::parser::Identifier;
use crate::parser::PendingArg;
use crate::parser::{ArgMatches, MatchedArg, SubCommand, ValueSource};
use crate::util::AnyValue;
use crate::util::FlatMap;
use crate::util::Id;
use crate::INTERNAL_ERROR_MSG;

#[derive(Debug, Default)]
pub(crate) struct ArgMatcher {
    matches: ArgMatches,
    pending: Option<PendingArg>,
}
```

`ArgMatcher` only derives `Debug` and `Default`, not `Clone`. No `Clone` import or derive is present in this definition, so `let matcher_snapshot = matcher.clone();` would not compile unless there is a separate manual `impl Clone for ArgMatcher` elsewhere.

